public void processPurchTradeLimit()
{
    AgreementLineQuantityCommitment aLine;
    LineAmount totalAgreementAmt;
    VendTable vendTable;
    ETGACFParameters    _eTGACFParameters = ETGACFParameters::find();

    if(_eTGACFParameters.EnableTradeLimit == NoYes::Yes && purchAgreementHeader.vendTable().ETGApplicableTradeLimit == NoYes::Yes)
    {
        while select aLine where aLine.Agreement == purchAgreementHeader.RecId
        {
            totalAgreementAmt += aLine.lineAmount();
        }

        if(totalAgreementAmt != 0)
        {
            vendTable = VendTable::find(purchAgreementHeader.VendAccount, true);
            if(totalAgreementAmt > vendTable.ETGRemainingTradeLimitPurchReal)
            {
                throw Error(strFmt("@ETG:ErrorTradeLimit1", totalAgreementAmt, vendTable.ETGRemainingTradeLimitPurchReal));
            }

            ttsbegin;
            vendTable.ETGRemainingTradeLimitPurchReal = vendTable.ETGRemainingTradeLimitPurchReal - totalAgreementAmt;
            vendTable.doUpdate();
            ttscommit;
        }
    }
}

